import 'package:flutter/material.dart'; void main()=>runApp(const App()); class App extends StatelessWidget{const App({super.key});@override Widget build(BuildContext c)=>MaterialApp(debugShowCheckedModeBanner:false,title:'MDM OpsFlow',theme:ThemeData(useMaterial3:true,colorScheme:ColorScheme.fromSeed(seedColor:const Color(0xFF2563EB))),home:const Home());} class Home extends StatefulWidget{const Home({super.key});State<Home> createState()=>_Home();} class _Home extends State<Home>{bool es=false;Widget tile(IconData i,String s)=>Card(child:ListTile(leading:Icon(i),title:Text(s),trailing:const Icon(Icons.chevron_right)));@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('MDM OpsFlow'),actions:[TextButton(onPressed:()=>setState(()=>es=!es),child:Text(es?'English':'Español'))]),body:ListView(padding:const EdgeInsets.all(20),children:[Text(es?'Panel principal':'Dashboard',style:Theme.of(c).textTheme.headlineMedium),tile(Icons.camera_alt_outlined,es?'Escanear documento':'Scan document'),tile(Icons.access_time,es?'Marcar entrada':'Clock in'),tile(Icons.health_and_safety,es?'Seguridad':'Safety'),tile(Icons.auto_awesome,es?'Copiloto de IA':'AI Copilot')]));}}
